var e=JSON.parse(`[{"id":"L2_1","type":"dialog","speaker":"PRESIDENT_PROMISE_NULL_NPC","text":{"KOREA":"시뮬레이션 세팅은 다 끝났니?","JPN":"シミュレーションセッティングは全部終わったの？","ENG":"Have you finished setting up the simulation?","TWN":"都設定好了嗎？"},"stage":{"bg":"DATABASE_02","slots":{"L":null,"C":{"char_id":"PRESIDENT_PROMISE_NULL_NPC","face":"UNIT_IDLE"},"R":null}}},{"id":"L4_1","type":"dialog","speaker":"CHAIR_SCHOOL_NULL_NULL","text":{"KOREA":"네…... 리소스도 다 적용했고… 시스템 안정화도 완벽해요.","JPN":"はい……リソースも全部適用して……システムの安定化も完璧。","ENG":"Yes... All the resources have been applied... and the system stabilization is also perfect.","TWN":"是…素材也都套用進去了…系統也沒問題。"},"stage":{"bg":"DATABASE_02","slots":{"L":null,"C":{"char_id":"CHAIR_SCHOOL_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L5_1","type":"dialog","speaker":"CHAIR_SCHOOL_NULL_NULL","text":{"KOREA":"흠냐… 이제 입장만 해주시면 돼요….","JPN":"むにゃ……もうログインするだけ……","ENG":"*Yawn* All that is left is to enter...","TWN":"哈啊…現在可以進去囉…"},"stage":{"bg":"DATABASE_02","slots":{"L":null,"C":{"char_id":"CHAIR_SCHOOL_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L7_1","type":"dialog","speaker":"PRESIDENT_PROMISE_NULL_NPC","text":{"KOREA":"많이 못 잤나 보구나. 정말 고생했어.","JPN":"あまり寝てないみたいね。本当にご苦労様。","ENG":"Guess you didn't sleep much. Great work, though.","TWN":"你好像沒睡飽的樣子，真是辛苦你了。"},"stage":{"bg":"DATABASE_02","slots":{"L":null,"C":{"char_id":"PRESIDENT_PROMISE_NULL_NPC","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L9_1","type":"dialog","speaker":"CHAIR_SCHOOL_NULL_NULL","text":{"KOREA":"쿨쿨…….","JPN":"ぐーぐー……","ENG":"Zzz...","TWN":"呼嚕……"},"stage":{"bg":"DATABASE_02","slots":{"L":null,"C":{"char_id":"PRESIDENT_PROMISE_NULL_NPC","face":"UNIT_IDLE"},"R":null}}},{"id":"L10_1","type":"dialog","speaker":"PRESIDENT_PROMISE_NULL_NPC","text":{"KOREA":"좋아. 늦기 전에 바로 접속해야겠다.","JPN":"よし。遅くなる前にすぐアクセスしないと。","ENG":"All right. I should log in right now before it gets any later.","TWN":"好，那就趕快登入吧。"},"stage":{"bg":"DATABASE_02","slots":{"L":null,"C":{"char_id":"PRESIDENT_PROMISE_NULL_NPC","face":"UNIT_IDLE"},"R":null}}},{"id":"L12_1","type":"dialog","speaker":"PRESIDENT_SCHOOL_NULL_NULL","text":{"KOREA":"네. 금일 테스트는 전부 기록해 두겠습니다.","JPN":"はい。今日のテストはすべて記録しておきます。","ENG":"Yes. I will keep a record of all the tests done today.","TWN":"是，今天的測試全都會記錄下來。"},"stage":{"bg":"DATABASE_02","slots":{"L":null,"C":{"char_id":"PRESIDENT_SCHOOL_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L14_1","type":"dialog","speaker":"PRESIDENT_PROMISE_NULL_NPC","text":{"KOREA":"후훗, 정말 고마워.","JPN":"ふふっ、本当にありがとう。","ENG":"Ha ha. Thanks a lot.","TWN":"呵呵，謝謝你。"},"stage":{"bg":"DATABASE_02","slots":{"L":null,"C":{"char_id":"PRESIDENT_PROMISE_NULL_NPC","face":"UNIT_LAUGH"},"R":null}}},{"id":"L15_1","type":"dialog","speaker":"PRESIDENT_PROMISE_NULL_NPC","text":{"KOREA":"시뮬레이션을 직접 플레이해 보는 건 오랜만이네.","JPN":"シミュレーションを直接プレイしてみるのは久しぶりね。","ENG":"It's been a long time since I played a simulation myself.","TWN":"好久沒有進行模擬測試了。"},"stage":{"bg":"DATABASE_02","slots":{"L":null,"C":{"char_id":"PRESIDENT_PROMISE_NULL_NPC","face":"UNIT_IDLE"},"R":null}}},{"id":"L16_1","type":"dialog","speaker":"PRESIDENT_PROMISE_NULL_NPC","text":{"KOREA":"둘러볼 필드와 몬스터들도 많을 테니까 혼자서는 조금 오래 걸릴지도….","JPN":"フィールドとモンスターも多いはずだから、一人だとちょっと時間がかかるかも……","ENG":"It might take me a while because of the vast field and all the monsters...","TWN":"地圖那麼大，怪物又多，一個人好像會很花時間…"},"stage":{"bg":"DATABASE_02","slots":{"L":null,"C":{"char_id":"PRESIDENT_PROMISE_NULL_NPC","face":"UNIT_LAUGH"},"R":null}}},{"id":"L17_1","type":"dialog","speaker":"PRESIDENT_PROMISE_NULL_NPC","text":{"KOREA":"그럼 바로 준비해 줘.","JPN":"じゃあ、すぐ準備して。","ENG":"Then, get it ready right away.","TWN":"那就準備開始吧。"},"stage":{"bg":"DATABASE_02","slots":{"L":null,"C":{"char_id":"PRESIDENT_PROMISE_NULL_NPC","face":"UNIT_IDLE"},"R":null}}},{"id":"L20_1","type":"dialog","speaker":"AI_SCHOOL_NULL_NULL","text":{"KOREA":"신원 확인 완료. 환영합니다 이사장 님.","JPN":"本人確認完了。ようこそ、理事長。","ENG":"Verification complete. Welcome, Ms. Chairwoman.","TWN":"身分確認完畢。歡迎理事長。"},"stage":{"bg":"BLACK","slots":{"L":null,"C":null,"R":null}}},{"id":"L21_1","type":"dialog","speaker":"AI_SCHOOL_NULL_NULL","text":{"KOREA":"시뮬레이션 베타 테스트 모드로 입장합니다.","JPN":"シミュレーションベータテストモードにログインします。","ENG":"Entering simulation beta test mode.","TWN":"現在進入模擬測試模式。"},"stage":{"bg":"BLACK","slots":{"L":null,"C":null,"R":null}}},{"id":"L24_1","type":"dialog","speaker":"DAIN_PROMISE_NULL_NULL","text":{"KOREA":"다행이다. 잘 접속된 것 같아.","JPN":"よかった。ちゃんとアクセスできたみたい。","ENG":"Nice. Connection seems good.","TWN":"太好了，好像有順利登入。"},"stage":{"bg":"SUMMER_CLIFF","slots":{"L":null,"C":{"char_id":"DAIN_PROMISE_NULL_NULL","face":"UNIT_LAUGH"},"R":null}}},{"id":"L25_1","type":"dialog","speaker":"DAIN_PROMISE_NULL_NULL","text":{"KOREA":"음…. 접속한 건 아직 나뿐인가?","JPN":"うーん……アクセスしたのはまだ私だけかな？","ENG":"Mm... Am I the only one logged in right now?","TWN":"嗯…現在只有我一個人登入嗎？"},"stage":{"bg":"SUMMER_CLIFF","slots":{"L":null,"C":{"char_id":"DAIN_PROMISE_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L27_1","type":"dialog","speaker":"PRESIDENT_SCHOOL_NULL_NULL","text":{"KOREA":"네. 이사장님의 좌표는 친구분도 알고 있을 겁니다.","JPN":"はい。理事長の座標はご友人の方も知っているはずです。","ENG":"Yes. Your friend should know your coordinates.","TWN":"是的，理事長的朋友應該也知道你的座標。"},"stage":{"bg":"SUMMER_CLIFF","slots":{"L":null,"C":{"char_id":"PRESIDENT_SCHOOL_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L28_1","type":"dialog","speaker":"PRESIDENT_SCHOOL_NULL_NULL","text":{"KOREA":"친구분이 접속하실 때까진 저희가 계속 모니터링 하겠습니다.","JPN":"ご友人の方がアクセスするまで、私たちが続けてモニタリングします。","ENG":"We'll be monitoring you until your friend comes.","TWN":"在理事長的朋友登入前，我們會持續觀察。"},"stage":{"bg":"SUMMER_CLIFF","slots":{"L":null,"C":{"char_id":"PRESIDENT_SCHOOL_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L29_1","type":"dialog","speaker":"PRESIDENT_SCHOOL_NULL_NULL","text":{"KOREA":"입고 계신 의상도 잘 어울리세요. 친구분께서 디자인한 건가요?","JPN":"その衣装もとてもお似合いですよ。ご友人の方がデザインされたのですか？","ENG":"The clothes suit you nicely. Did your friend design them?","TWN":"理事長身上的造型也很好看呢。是朋友設計的嗎？"},"stage":{"bg":"SUMMER_CLIFF","slots":{"L":null,"C":{"char_id":"PRESIDENT_SCHOOL_NULL_NULL","face":"UNIT_LAUGH"},"R":null}}},{"id":"L31_1","type":"dialog","speaker":"DAIN_PROMISE_NULL_NULL","text":{"KOREA":"후훗, 그러게. 오늘도 마침 할로윈이니까 그에 맞는 복장을….","JPN":"ふふっ、そうよ。今日はちょうどハロウィンだし、それに相応しい服装を……","ENG":"Ha ha, I think so too. Guess it fits the theme of Halloween–","TWN":"呵呵，對啊。剛好今天是萬聖節，所以特地配合…"},"stage":{"bg":"SUMMER_CLIFF","slots":{"L":null,"C":{"char_id":"DAIN_PROMISE_NULL_NULL","face":"UNIT_LAUGH"},"R":null}}},{"id":"L32_1","type":"dialog","speaker":"DAIN_PROMISE_NULL_NULL","text":{"KOREA":"어라……?","JPN":"あれ……？","ENG":"Huh...?","TWN":"嗯……？"},"stage":{"bg":"SUMMER_CLIFF","slots":{"L":null,"C":{"char_id":"DAIN_PROMISE_NULL_NULL","face":"UNIT_SURPRISE"},"R":null}}},{"id":"L35_1","type":"dialog","speaker":"DAIN_GAMECIRCLE_NULL_NULL","text":{"KOREA":"에헤헤, 다들 멋지게 잘 그려진 것 같아.","JPN":"えへへ、みんなカッコよくちゃんと描けたみたい。","ENG":"Eh he he, I think they all turned out great.","TWN":"嘿嘿嘿，把大家都畫得很好呢。"},"stage":{"bg":"CIRCLEROOM","slots":{"L":null,"C":{"char_id":"DAIN_GAMECIRCLE_NULL_NULL","face":"UNIT_LAUGH"},"R":null}}},{"id":"L37_1","type":"dialog","speaker":"BORA_GAMECIRCLE_NULL_NULL","text":{"KOREA":"…….","JPN":"……","ENG":"...","TWN":"……"},"stage":{"bg":"CIRCLEROOM","slots":{"L":null,"C":{"char_id":"BORA_GAMECIRCLE_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L39_1","type":"dialog","speaker":"DAIN_GAMECIRCLE_NULL_NULL","text":{"KOREA":"앗, 보라야. 옆에 있었어? 깜짝 놀랐네.","JPN":"あっ、シホちゃん。隣にいたの？　びっくりした。","ENG":"Oh, Bora. Were you there this whole time? You startled me.","TWN":"啊！寶拉，你一直在我旁邊嗎？被你嚇到！"},"stage":{"bg":"CIRCLEROOM","slots":{"L":null,"C":{"char_id":"DAIN_GAMECIRCLE_NULL_NULL","face":"UNIT_SURPRISE"},"R":null}}},{"id":"L40_1","type":"dialog","speaker":"BORA_GAMECIRCLE_NULL_NULL","text":{"KOREA":"새로운 디자인이야……? 괴수…….","JPN":"新しいデザイン……？　怪獣……","ENG":"Is that a new design...? A monster...?","TWN":"新設計的嗎……？怪物……"},"stage":{"bg":"CIRCLEROOM","slots":{"L":null,"C":{"char_id":"BORA_GAMECIRCLE_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L43_1","type":"dialog","speaker":"DAIN_GAMECIRCLE_NULL_NULL","text":{"KOREA":"그건 아니고, 판타지 세계관의 용사들을 그려봤어.","JPN":"そうじゃなくて、ファンタジー世界の勇者たちを描いてみたの。","ENG":"Not quite. I drew the heroes for our fantasy world.","TWN":"不是啦，我在嘗試畫奇幻世界觀的勇士。"},"stage":{"bg":"CIRCLEROOM","slots":{"L":{"char_id":"DAIN_GAMECIRCLE_NULL_NULL","face":"UNIT_LAUGH"},"C":null,"R":{"char_id":"BORA_GAMECIRCLE_NULL_NULL","face":"UNIT_IDLE"}}}}]`);export{e as default};